const input = $input.item.json;
const body = input.body || {};

const user_id = input.user_id || body.user_id || '';
const week_number = parseInt(body.week_number) || 1;
const month = body.month || '';
const platforms = body.platforms || ['linkedin'];
const pipeline_run_id = body.pipeline_run_id || null;
const callback_url = body.callback_url || null;
const business_url = body.business_url || '';
const industry = body.industry || '';

// Calculate step number: Week 1 = step 3, Week 4 = step 6
const step = week_number + 2;

return {
  json: {
    user_id,
    week_number,
    month,
    platforms,
    pipeline_run_id,
    callback_url,
    business_url,
    industry,
    step
  }
};

const params = $('Extract Params').item.json;
const themeRaw = $('Read Theme').item.json;
const icpRaw = $('Read ICP').item.json;
const productsRaw = $('Read Products').item.json;

// Parse theme (PostgREST returns array)
const themes = Array.isArray(themeRaw) ? themeRaw : [themeRaw];
const theme = themes[0] || {};
const campaign = theme.campaigns || {};
const campaign_id = campaign.id || theme.campaign_id || null;
const show_name = campaign.show_name || 'Content Series';
const theme_id = theme.id || null;
const theme_name = theme.theme_name || 'Weekly Theme';
const inspirational_theme = theme.inspirational_theme || '';
const season_arc = theme.season_arc || '';

// Parse daily assignments from content_types JSONB
let dailyAssignments = [];
if (theme.content_types && Array.isArray(theme.content_types)) {
  dailyAssignments = theme.content_types;
} else if (typeof theme.content_types === 'string') {
  try { dailyAssignments = JSON.parse(theme.content_types); } catch(e) { dailyAssignments = []; }
}

// Parse ICP
const icps = Array.isArray(icpRaw) ? icpRaw : [icpRaw];
const icp = icps[0] || {};
const icp_summary = (icp.icp_summary || '').substring(0, 500);
const recommended_hashtags = icp.recommended_hashtags || [];

// Parse products into lookup map
const products = Array.isArray(productsRaw) ? productsRaw : (productsRaw ? [productsRaw] : []);
const productMap = {};
for (const p of products) {
  if (p.id) productMap[p.id] = p;
}

// Decide video days: days 2, 4, 6 (and optionally 7 for 4 scripts)
const videoDays = [2, 4, 6];
if (params.week_number % 2 === 0) videoDays.push(7); // Alternate weeks get 4 videos

// Calculate scheduled dates
const month = params.month; // e.g., "2026-03"
const weekNum = params.week_number;
const platforms = params.platforms;

// Build items for the daily loop (7 days)
const dailyItems = [];
for (let dayIdx = 0; dayIdx < 7; dayIdx++) {
  const dayNumber = dayIdx + 1;
  const assignment = dailyAssignments[dayIdx] || {};
  const product_id = assignment.product_id || null;
  const product = product_id ? (productMap[product_id] || {}) : {};
  const product_name = assignment.product_name || product.name || 'Featured Product';
  const product_description = product.description || '';
  const product_price = product.price || '';
  const product_image_url = product.image_url || null;
  const topic = assignment.topic || 'Engagement';
  const content_angle = assignment.content_angle || '';
  const isVideoDay = videoDays.includes(dayNumber);

  // Calculate scheduled_date: month start + (weekNum-1)*7 + (dayNumber-1)
  let scheduledDate = '';
  if (month) {
    const parts = month.split('-');
    const year = parseInt(parts[0]);
    const mon = parseInt(parts[1]) - 1;
    const dayOfMonth = (weekNum - 1) * 7 + dayNumber;
    const d = new Date(year, mon, dayOfMonth);
    // Handle month overflow gracefully
    if (d.getMonth() !== mon) {
      // Day exceeds month length, use last day of month
      const lastDay = new Date(year, mon + 1, 0).getDate();
      scheduledDate = `${year}-${String(mon + 1).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;
    } else {
      scheduledDate = `${year}-${String(mon + 1).padStart(2, '0')}-${String(dayOfMonth).padStart(2, '0')}`;
    }
  }

  // Build Claude prompt for this day (all platforms in one call)
  const platformRules = [];
  for (const plat of platforms) {
    const p = plat.toLowerCase();
    if (p === 'linkedin') platformRules.push('- LinkedIn: 1300-1800 chars, thought leadership tone, line breaks between paragraphs, 3-5 professional hashtags, product CTA');
    if (p === 'instagram') platformRules.push('- Instagram: 150-300 char caption, 20-30 hashtags in separate first_comment field, emoji allowed, product CTA');
    if (p === 'x') platformRules.push('- X: 5-7 tweet thread (each under 280 chars, numbered), punchy and conversational, product CTA in last tweet');
    if (p === 'youtube') platformRules.push('- YouTube: Community post format, story-driven, 200-400 chars, product CTA');
  }

  const prompt = `Generate social media posts for these platforms: ${platforms.join(', ')}\n\nContext:\n- Show: "${show_name}"\n- Season ${weekNum}: "${theme_name}" -- ${inspirational_theme}\n- Day's Product: ${product_name} -- ${product_description}${product_price ? ' (Price: ' + product_price + ')' : ''}\n- Day's Topic: "${topic}"\n- Content Angle: "${content_angle}"\n- ICP: ${icp_summary}\n\nPlatform rules:\n${platformRules.join('\n')}\n\nReturn JSON:\n{\n  "posts": {\n    "linkedin": { "text": "...", "hashtags": [...], "cta": "..." },\n    "instagram": { "text": "...", "hashtags": [...], "first_comment": "...", "cta": "..." },\n    "x": { "text": "...", "hashtags": [...], "cta": "..." },\n    "youtube": { "text": "...", "hashtags": [...], "cta": "..." }\n  },\n  "image_prompt": "Product + lifestyle blend image prompt for the day (max 500 chars)"\n}\nOnly include platforms listed. Product CTA ties back to featured product.\n\nAlso generate a hero image prompt: product as hero in aspirational lifestyle scene, matching the season theme, 1:1 aspect ratio, photorealistic, no text overlays.`;

  dailyItems.push({
    day_number: dayNumber,
    product_id,
    product_name,
    product_description,
    product_price,
    product_image_url,
    topic,
    content_angle,
    is_video_day: isVideoDay,
    scheduled_date: scheduledDate,
    prompt,
    // Carry context forward
    user_id: params.user_id,
    campaign_id,
    theme_id,
    show_name,
    theme_name,
    week_number: weekNum,
    platforms,
    pipeline_run_id: params.pipeline_run_id,
    callback_url: params.callback_url,
    step: params.step,
    icp_summary,
    recommended_hashtags,
    inspirational_theme
  });
}

return dailyItems.map(item => ({ json: item }));

const day = $input.item.json;

const apiBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  messages: [
    {
      role: 'user',
      content: day.prompt
    }
  ]
};

return {
  json: {
    apiBody: JSON.stringify(apiBody),
    ...day
  }
};

const day = $('Prepare Day Claude Prompt').item.json;
const claudeResponse = $input.item.json;

// Extract text from Claude response
let raw = '';
if (claudeResponse.content && claudeResponse.content[0]) {
  raw = claudeResponse.content[0].text;
} else if (typeof claudeResponse === 'string') {
  raw = claudeResponse;
}

// Robust JSON parsing (strip markdown fences, extract JSON)
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try {
    parsed = JSON.parse(stripped);
  } catch(e2) {
    const match = stripped.match(/[\[{][\s\S]*[\]}]/);
    if (match) {
      try {
        parsed = JSON.parse(match[0]);
      } catch(e3) {
        parsed = { posts: {}, image_prompt: 'Professional product lifestyle image, photorealistic, 1:1 aspect ratio' };
      }
    } else {
      parsed = { posts: {}, image_prompt: 'Professional product lifestyle image, photorealistic, 1:1 aspect ratio' };
    }
  }
}

const posts = parsed.posts || {};
const image_prompt = parsed.image_prompt || 'Professional product lifestyle image, photorealistic, 1:1 aspect ratio';

// Map to content_items rows
const contentItems = [];
const platforms = day.platforms || [];

for (const platform of platforms) {
  const plat = platform.toLowerCase();
  const post = posts[plat] || {};

  contentItems.push({
    user_id: day.user_id,
    campaign_id: day.campaign_id,
    theme_id: day.theme_id,
    title: `${day.show_name} S${day.week_number} Day ${day.day_number} - ${plat}`,
    content: post.text || JSON.stringify(post),
    content_type: 'text',
    platform: plat,
    scheduled_date: day.scheduled_date,
    status: 'pending_review',
    image_prompt: image_prompt,
    product_id: day.product_id,
    hashtags: post.hashtags || [],
    first_comment: post.first_comment || null
  });
}

return {
  json: {
    day_number: day.day_number,
    content_items: contentItems,
    image_prompt: image_prompt,
    is_video_day: day.is_video_day,
    scheduled_date: day.scheduled_date,
    product_id: day.product_id,
    product_name: day.product_name,
    product_description: day.product_description,
    product_image_url: day.product_image_url,
    topic: day.topic,
    content_angle: day.content_angle,
    // Carry context forward
    user_id: day.user_id,
    campaign_id: day.campaign_id,
    theme_id: day.theme_id,
    show_name: day.show_name,
    theme_name: day.theme_name,
    week_number: day.week_number,
    platforms: day.platforms,
    pipeline_run_id: day.pipeline_run_id,
    callback_url: day.callback_url,
    step: day.step,
    icp_summary: day.icp_summary,
    inspirational_theme: day.inspirational_theme
  }
};

// Collect all content items from the daily loop
const allItems = $('Parse Day Content').all();

const allContentItems = [];
const allImagePrompts = [];
const videoDays = [];

for (const item of allItems) {
  const data = item.json;
  if (data.content_items && Array.isArray(data.content_items)) {
    allContentItems.push(...data.content_items);
  }
  allImagePrompts.push({
    day_number: data.day_number,
    image_prompt: data.image_prompt,
    scheduled_date: data.scheduled_date
  });
  if (data.is_video_day) {
    videoDays.push({
      day_number: data.day_number,
      product_id: data.product_id,
      product_name: data.product_name,
      product_description: data.product_description,
      product_image_url: data.product_image_url,
      topic: data.topic,
      content_angle: data.content_angle,
      scheduled_date: data.scheduled_date
    });
  }
}

// Carry forward context from first item
const ctx = allItems[0] ? allItems[0].json : {};

return {
  json: {
    content_items: allContentItems,
    image_prompts: allImagePrompts,
    video_days: videoDays,
    content_count: allContentItems.length,
    user_id: ctx.user_id,
    campaign_id: ctx.campaign_id,
    theme_id: ctx.theme_id,
    show_name: ctx.show_name,
    theme_name: ctx.theme_name,
    week_number: ctx.week_number,
    platforms: ctx.platforms,
    pipeline_run_id: ctx.pipeline_run_id,
    callback_url: ctx.callback_url,
    step: ctx.step,
    icp_summary: ctx.icp_summary,
    inspirational_theme: ctx.inspirational_theme
  }
};

const data = $input.item.json;
const videoDays = data.video_days || [];

// Build Perplexity prompt for trending audio research
const month = data.week_number ? `Week ${data.week_number}` : 'this month';
const industry = data.theme_name || 'business';

const prompt = `What are the top 10 trending sounds/songs on Instagram Reels and YouTube Shorts right now? For each, provide: song name, artist, and which platform it's trending on. Focus on sounds that work well for ${industry} content. Return as JSON array: [{"name": "...", "artist": "...", "platform": "Instagram|YouTube"}]`;

return {
  json: {
    ...data,
    perplexity_prompt: prompt,
    has_video_days: videoDays.length > 0
  }
};

const prevData = $('Prepare Trending Audio Prompt').item.json;
const perplexityResponse = $input.item.json;

// Extract trending audio from Perplexity response
let trendingAudioText = '';
try {
  if (perplexityResponse.choices && perplexityResponse.choices[0]) {
    trendingAudioText = perplexityResponse.choices[0].message.content;
  }
} catch(e) {
  trendingAudioText = 'Trending audio data unavailable';
}

// Parse trending audio JSON if possible
let trendingAudio = [];
try {
  const raw = trendingAudioText;
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch(e) {
    const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
    try {
      parsed = JSON.parse(stripped);
    } catch(e2) {
      const match = stripped.match(/\[[\s\S]*\]/);
      if (match) parsed = JSON.parse(match[0]);
    }
  }
  if (Array.isArray(parsed)) trendingAudio = parsed;
  else if (parsed && Array.isArray(parsed.trending)) trendingAudio = parsed.trending;
} catch(e) {
  // Keep as text
}

// Now prepare video script prompts for each video day
const videoDays = prevData.video_days || [];
const videoPrompts = [];

for (const vday of videoDays) {
  const audioRecs = trendingAudio.slice(0, 4).map(a => `${a.name} by ${a.artist} (${a.platform})`).join(', ') || trendingAudioText.substring(0, 500);

  const prompt = `Create a professional, production-ready 30-second video script.\n\nProduct: ${vday.product_name} - ${vday.product_description || ''}\nProduct Image/URL: ${vday.product_image_url || 'N/A'}\nTheme: ${vday.topic}\nContent Angle: ${vday.content_angle || ''}\nTarget Audience: ${prevData.icp_summary || ''}\nSeason Theme: ${prevData.inspirational_theme || ''}\nTrending Audio Options: ${audioRecs}\n\nReturn a JSON object with this EXACT structure:\n{\n  "title": "Video title",\n  "duration": "30 seconds",\n  "platforms": ["Instagram Reels", "YouTube Shorts"],\n  "trending_audio": [\n    { "name": "...", "artist": "...", "platform": "Instagram" },\n    { "name": "...", "artist": "...", "platform": "YouTube" }\n  ],\n  "sections": {\n    "hook": { "timing": "0:00-0:03", "script": "...", "camera": "...", "b_roll": "...", "on_screen_text": "..." },\n    "setup": { "timing": "0:03-0:10", "script": "...", "camera": "...", "b_roll": "...", "on_screen_text": "..." },\n    "value": { "timing": "0:10-0:25", "script": "...", "camera": "...", "b_roll": "...", "on_screen_text": "...", "key_points": [...] },\n    "cta": { "timing": "0:25-0:30", "script": "...", "camera": "...", "on_screen_text": "...", "action": "..." }\n  },\n  "music_mood": "...",\n  "thumbnail_idea": "...",\n  "production_notes": "...",\n  "product_url": "${vday.product_image_url || ''}",\n  "product_image": "${vday.product_image_url || ''}"\n}`;

  videoPrompts.push({
    ...vday,
    video_prompt: prompt
  });
}

return {
  json: {
    ...prevData,
    trending_audio_raw: trendingAudioText,
    trending_audio: trendingAudio,
    video_prompts: videoPrompts
  }
};

const data = $input.item.json;
const videoPrompts = data.video_prompts || [];

// Output each video prompt as a separate item for the loop
return videoPrompts.map(vp => ({
  json: {
    ...vp,
    user_id: data.user_id,
    campaign_id: data.campaign_id,
    theme_id: data.theme_id,
    show_name: data.show_name,
    week_number: data.week_number,
    platforms: data.platforms,
    pipeline_run_id: data.pipeline_run_id,
    callback_url: data.callback_url,
    step: data.step,
    all_content_items: data.content_items,
    all_image_prompts: data.image_prompts,
    content_count: data.content_count,
    trending_audio_raw: data.trending_audio_raw,
    trending_audio: data.trending_audio
  }
}));

const vday = $input.item.json;

const apiBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  messages: [
    {
      role: 'user',
      content: vday.video_prompt
    }
  ]
};

return {
  json: {
    apiBody: JSON.stringify(apiBody),
    ...vday
  }
};

const vday = $('Prepare Video Claude Prompt').item.json;
const claudeResponse = $input.item.json;

// Extract text from Claude response
let raw = '';
if (claudeResponse.content && claudeResponse.content[0]) {
  raw = claudeResponse.content[0].text;
} else if (typeof claudeResponse === 'string') {
  raw = claudeResponse;
}

// Robust JSON parsing
let videoScript;
try {
  videoScript = JSON.parse(raw);
} catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try {
    videoScript = JSON.parse(stripped);
  } catch(e2) {
    const match = stripped.match(/[{][\s\S]*[}]/);
    if (match) {
      try {
        videoScript = JSON.parse(match[0]);
      } catch(e3) {
        videoScript = { title: 'Video Script', error: 'Failed to parse' };
      }
    } else {
      videoScript = { title: 'Video Script', error: 'Failed to parse' };
    }
  }
}

// Add product references
videoScript.product_url = vday.product_image_url || '';
videoScript.product_image = vday.product_image_url || '';

// Create video content_item for each video-capable platform
const videoItems = [];
const videoPlatforms = (vday.platforms || []).filter(p => {
  const pl = p.toLowerCase();
  return pl === 'instagram' || pl === 'youtube';
});

for (const plat of (videoPlatforms.length > 0 ? videoPlatforms : ['instagram'])) {
  videoItems.push({
    user_id: vday.user_id,
    campaign_id: vday.campaign_id,
    theme_id: vday.theme_id,
    title: `${vday.show_name} S${vday.week_number} Day ${vday.day_number} - ${plat.toLowerCase()} video`,
    content: videoScript.title || 'Video Script',
    content_type: 'video',
    platform: plat.toLowerCase(),
    scheduled_date: vday.scheduled_date,
    status: 'pending_review',
    image_prompt: null,
    product_id: vday.product_id,
    video_script: videoScript,
    hashtags: [],
    first_comment: null
  });
}

return {
  json: {
    video_content_items: videoItems,
    day_number: vday.day_number,
    video_script: videoScript
  }
};

// Collect all video content items from the video script loop
const allVideoItems = $('Parse Video Script').all();

const videoContentItems = [];
for (const item of allVideoItems) {
  if (item.json.video_content_items) {
    videoContentItems.push(...item.json.video_content_items);
  }
}

// Get the main data from Prepare Video Loop Items (first item has all context)
const ctx = $('Prepare Video Loop Items').first().json;

return {
  json: {
    content_items: ctx.all_content_items || [],
    video_content_items: videoContentItems,
    image_prompts: ctx.all_image_prompts || [],
    content_count: (ctx.content_count || 0) + videoContentItems.length,
    user_id: ctx.user_id,
    campaign_id: ctx.campaign_id,
    theme_id: ctx.theme_id,
    show_name: ctx.show_name,
    week_number: ctx.week_number,
    platforms: ctx.platforms,
    pipeline_run_id: ctx.pipeline_run_id,
    callback_url: ctx.callback_url,
    step: ctx.step
  }
};

const data = $input.item.json;

// Merge text content_items + video content_items into one batch
const allItems = [...(data.content_items || []), ...(data.video_content_items || [])];

// Prepare the batch insert body
// Ensure all items have correct fields for Supabase INSERT
const batchBody = allItems.map(item => ({
  user_id: item.user_id,
  campaign_id: item.campaign_id,
  theme_id: item.theme_id,
  title: item.title,
  content: item.content,
  content_type: item.content_type,
  platform: item.platform,
  scheduled_date: item.scheduled_date,
  status: 'pending_review',
  image_prompt: item.image_prompt || null,
  product_id: item.product_id || null,
  video_script: item.video_script ? JSON.stringify(item.video_script) : null,
  hashtags: item.hashtags && item.hashtags.length > 0 ? `{${item.hashtags.map(h => `"${h.replace(/"/g, '\\"')}"`).join(',')}}` : null,
  first_comment: item.first_comment || null
}));

return {
  json: {
    batch_body: batchBody,
    batch_count: batchBody.length,
    image_prompts: data.image_prompts || [],
    user_id: data.user_id,
    campaign_id: data.campaign_id,
    week_number: data.week_number,
    pipeline_run_id: data.pipeline_run_id,
    callback_url: data.callback_url,
    step: data.step
  }
};

const prevData = $('Prepare Batch Insert').item.json;
const insertResult = $input.item.json;

// Extract inserted content items for image URL mapping later
const insertedItems = Array.isArray(insertResult) ? insertResult : [insertResult];

// Prepare image prompts as loop items
const imagePrompts = prevData.image_prompts || [];

return imagePrompts.map(ip => ({
  json: {
    day_number: ip.day_number,
    image_prompt: ip.image_prompt,
    scheduled_date: ip.scheduled_date,
    campaign_id: prevData.campaign_id,
    user_id: prevData.user_id,
    week_number: prevData.week_number,
    pipeline_run_id: prevData.pipeline_run_id,
    callback_url: prevData.callback_url,
    step: prevData.step,
    batch_count: prevData.batch_count
  }
}));

const item = $input.item.json;
const imgItem = $('Image Generation Loop').item.json;

return {
  json: {
    ...item,
    pollCount: 0,
    taskId: item.data?.task_id || item.data?.taskId || item.task_id || item.taskId,
    day_number: imgItem.day_number,
    scheduled_date: imgItem.scheduled_date,
    campaign_id: imgItem.campaign_id,
    user_id: imgItem.user_id,
    week_number: imgItem.week_number,
    pipeline_run_id: imgItem.pipeline_run_id,
    callback_url: imgItem.callback_url,
    step: imgItem.step,
    batch_count: imgItem.batch_count
  }
};

const result = $input.item.json;
const prevData = $('Init Image Poll').item.json;
const pollCount = (prevData.pollCount || 0) + 1;

// Check status -- KIE uses 'succeeded' or 'success' or 'completed'
const status = result.output?.status || result.data?.state || result.status || 'processing';
const isReady = status === 'succeeded' || status === 'success' || status === 'completed';
const isTimeout = pollCount >= 12;
const isError = status === 'failed' || status === 'error';

// Extract image URL if ready
let imageUrl = null;
if (isReady) {
  // Try multiple response formats
  if (result.output?.works && result.output.works[0]?.resource?.url) {
    imageUrl = result.output.works[0].resource.url;
  } else if (result.data?.resultJson) {
    try {
      const parsed = JSON.parse(result.data.resultJson);
      if (parsed.resultUrls && parsed.resultUrls[0]) imageUrl = parsed.resultUrls[0];
    } catch(e) {}
  } else if (result.output?.image_url) {
    imageUrl = result.output.image_url;
  }
}

return {
  json: {
    ...prevData,
    pollCount,
    isComplete: isReady || isTimeout || isError,
    isSuccess: isReady && !!imageUrl,
    imageUrl,
    error: isTimeout ? 'Image generation timed out' : isError ? `Image failed: ${status}` : null
  }
};

// After image loop completes, prepare callback
const firstItem = $('Prepare Image Loop Items').first().json;

return {
  json: {
    pipeline_run_id: firstItem.pipeline_run_id,
    callback_url: firstItem.callback_url,
    step: firstItem.step,
    week_number: firstItem.week_number,
    batch_count: firstItem.batch_count,
    images_generated: 7
  }
};

// Error handler -- recover context and prepare error callback
const allItems = [];
try { allItems.push($('Extract Params').item.json); } catch(e) {}

const ctx = allItems[0] || {};
const pipeline_run_id = ctx.pipeline_run_id || null;
const callback_url = ctx.callback_url || null;
const step = ctx.step || 3;
const errorMessage = $input.item.json.message || $input.item.json.error || 'Content Studio execution failed';

return {
  json: {
    pipeline_run_id,
    callback_url,
    step,
    error_message: errorMessage,
    has_callback: !!callback_url
  }
};

// Handle skip-video path: no video days, go straight to batch insert
// Data comes from Has Video Days? which received from Prepare Video Script Prompts
const data = $input.item.json;

return {
  json: {
    content_items: data.content_items || [],
    video_content_items: [],
    image_prompts: data.image_prompts || [],
    content_count: data.content_count || 0,
    user_id: data.user_id,
    campaign_id: data.campaign_id,
    theme_id: data.theme_id,
    show_name: data.show_name,
    week_number: data.week_number,
    platforms: data.platforms,
    pipeline_run_id: data.pipeline_run_id,
    callback_url: data.callback_url,
    step: data.step
  }
};

// IF Success FALSE path -- image failed, skip update and continue loop
const data = $input.item.json;
return {
  json: {
    ...data,
    image_skipped: true
  }
};
